function mostrarConsumiblesPorCategoria(o){$("#categoriaActual").val(o),$.ajax({url:"/gestion/app/controller/ArsenalController.php",type:"GET",data:{action:"getConsumiblesPorCategoria",categoria_id:o},success:function(o){console.log(o);try{var a=JSON.parse(o),t='<table class="table table-bordered"><thead class="thead-dark"><tr><th>Nombre</th><th>Stock</th><th>Precio</th><th>Acción</th></tr></thead><tbody>';a.forEach(function(o){var a=parseFloat(o.precio),e=parseInt(o.stock),r=e<=0?"disabled":"";t+='<tr class="'+r+'"><td>'+o.nombre+"</td><td>"+e+"</td><td>"+a.toFixed(2)+'</td><td><button type="button" class="btn btn-success" onclick="agregarProducto('+o.id+", '"+o.nombre+"', "+a.toFixed(2)+", "+e+')">Agregar</button></td></tr>'}),t+="</tbody></table>",$("#consumiblesList").html(t)}catch(o){console.error("Error parsing JSON response:",o),$("#consumiblesList").html("<p>Error al cargar los consumibles.</p>")}},error:function(o,a,t){console.error("AJAX Error:",a,t),$("#consumiblesList").html("<p>Error al cargar los consumibles.</p>")}})}function agregarProducto(o,a,t,e){var r=productosSeleccionados.find(a=>a.id===o);r?r.cantidad<e?r.cantidad++:alert("No puedes agregar más de este producto. Stock máximo alcanzado."):productosSeleccionados.push({id:o,nombre:a,precio:t,cantidad:1,stock:e}),actualizarPrevisualizacion()}function actualizarPrevisualizacion(){var o=0;if(productosSeleccionados.length>0){var a='<ul class="list-group">';productosSeleccionados.forEach(function(t,e){var r=t.precio*t.cantidad;o+=r,a+='<li class="list-group-item d-flex justify-content-between align-items-center">'+t.nombre+" - Cantidad: "+t.cantidad+'<span><button type="button" class="btn btn-sm btn-primary" onclick="incrementarCantidad('+e+')">+</button> <button type="button" class="btn btn-sm btn-danger" onclick="decrementarCantidad('+e+')">-</button></span><span class="badge badge-primary badge-pill">$'+r.toFixed(2)+"</span></li>"}),a+="</ul>"}else a="<p>No hay productos seleccionados.</p>";$("#ventaPreview").html(a),$("#totalVenta").html("<h4>Total: $"+o.toFixed(2)+"</h4>"),$("#productosSeleccionados").val(JSON.stringify(productosSeleccionados))}function incrementarCantidad(o){productosSeleccionados[o].cantidad<productosSeleccionados[o].stock?(productosSeleccionados[o].cantidad++,actualizarPrevisualizacion()):alert("No puedes agregar más de este producto. Stock máximo alcanzado.")}function decrementarCantidad(o){productosSeleccionados[o].cantidad>1?(productosSeleccionados[o].cantidad--,actualizarPrevisualizacion()):(productosSeleccionados.splice(o,1),actualizarPrevisualizacion())}var productosSeleccionados=[];$("#ventaForm").on("submit",function(o){o.preventDefault(),0!==productosSeleccionados.length?$.ajax({url:"/gestion/app/controller/ArsenalController.php?action=createVentaConsumible",type:"POST",data:{productosSeleccionados:JSON.stringify(productosSeleccionados),metodo_pago:$("#metodo_pago").val()},success:function(o){var a=JSON.parse(o);a.success?(alert(a.success),productosSeleccionados=[],actualizarPrevisualizacion(),$("#ventaForm")[0].reset(),mostrarConsumiblesPorCategoria($("#categoriaActual").val())):a.error&&alert(a.error)},error:function(o,a,t){console.error("Error en la solicitud AJAX:",t),alert("Ocurrió un error. Inténtelo de nuevo.")}}):alert("Debes seleccionar al menos un producto para registrar la venta.")});